module multi_pipe_8bit
(
    input clk,
    input rst_n,
    input mul_en_in,
    input mul_a,
    input mul_b,
    output mul_en_out,
    output mul_out
);
reg [7:0] mul_a_reg, mul_b_reg;
reg [15:0] partial_products [7:0];
reg [15:0] sum [7:0];
reg [7:0] carry [7:0];
reg [3:0] stage;
reg mul_en_out_reg;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_a_reg <= 8'b0;
        mul_b_reg <= 8'b0;
        mul_en_out_reg <= 1'b0;
        stage <= 4'b0;
    end
    else begin
        if (mul_en_in) begin
            mul_a_reg <= mul_a;
            mul_b_reg <= mul_b;
            mul_en_out_reg <= 1'b1;
            stage <= 4'b0;
        end
        else begin
            mul_en_out_reg <= 1'b0;
        end
    end
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        for (int i = 0; i < 8; i++) begin
            partial_products[i] <= 16'b0;
        end
    end
    else begin
        for (int i = 0; i < 8; i++) begin
            partial_products[i] <= mul_a_reg[i] ? {8'b0, mul_b_reg} << i : 16'b0;
        end
    end
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        for (int i = 0; i < 8; i++) begin
            sum[i] <= 16'b0;
            carry[i] <= 1'b0;
        end
    end
    else begin
        sum[0] <= partial_products[0];
        carry[0] <= sum[0][15];
        for (int i = 1; i < 8; i++) begin
            {carry[i-1], sum[i]} <= partial_products[i] + {carry[i-1], sum[i-1]};
        end
    end
end
assign mul_en_out = mul_en_out_reg;
assign mul_out = sum[7];
endmodule
